63	function isFlipped(newCoord: Coord, oldCoord: Coord, line: Line) {
64	    const CCW = (a: Coord, b: Coord, c: Coord) => {
65	        return (b[0] - a[0]) * (c[1] - a[1]) - (c[0] - a[0]) * (b[1] - a[1]);
66	    };
67	    return (
68	        CCW(line[0], line[1], oldCoord) > 0 !==
69	        CCW(line[0], line[1], newCoord) > 0
70	    );
71	}
