93	/* Graphing interface. */
94	class FunctionGrapher extends React.Component<FunctionGrapherProps> {
95	    static defaultProps: DefaultFunctionGrapherProps = {
96	        graph: {
97	            range: [
98	                [-10, 10],
99	                [-10, 10],
100	            ],
101	            step: [1, 1],
102	        },
103	        coords: null,
104	        asymptote: null,
105	        isMobile: false,
106	    };
107	
108	    _coords = () => {
109	        const props = this.props;
110	        const graph = props.graph;
111	        const defaultModelCoords =
112	            props.model &&
113	            maybePointsFromNormalized(
114	                props.model.defaultCoords,
115	                graph.range,
116	                graph.step,
117	                graph.snapStep,
118	            );
119	        return props.coords || defaultModelCoords || null;
120	    };
121	
122	    _asymptote = () => {
123	        // Unlike coords, asymptotes are never null; see defaultPlotProps.
124	        return this.props.asymptote;
125	    };
126	
127	    renderPlot = () => {
128	        const model = this.props.model;
129	        const xRange = this.props.graph.range[0];
130	        const style = {
131	            stroke: this.props.isMobile
132	                ? KhanColors.BLUE_C
133	                : KhanColors.DYNAMIC,
134	            ...(this.props.isMobile ? {"stroke-width": 3} : {}),
135	        } as const;
136	
137	        const coeffs = model.getCoefficients(this._coords(), this._asymptote());
138	        if (!coeffs) {
139	            return;
140	        }
141	
142	        const functionProps = model.getPropsForCoeffs(coeffs, xRange);
143	        const Movable = movableTypeToComponent[model.movable];
144	        return (
145	            <Movable
146	                {...functionProps}
147	                key={this.props.model.url}
148	                range={xRange}
149	                style={style}
150	            />
151	        );
152	    };
153	
154	    renderAsymptote = () => {
155	        const model = this.props.model;
156	        const graph = this.props.graph;
157	        const asymptote = this._asymptote();
158	        const showAsymptote = asymptote?.length > 0;
159	        const dashed = {
160	            strokeDasharray: "- ",
161	        } as const;
162	
163	        return (
164	            showAsymptote && (
165	                <MovableLine
166	                    onMove={(newCoord, oldCoord) => {
167	                        // Calculate and apply displacement
168	                        const delta = kvector.subtract(newCoord, oldCoord);
169	                        const newAsymptote = this._asymptote().map((coord) =>
170	                            kvector.add(coord, delta),
171	                        );
172	                        this.props.onChange({
173	                            asymptote: newAsymptote,
174	                        });
175	                    }}
176	                    constraints={[
177	                        // @ts-expect-error - TS2339 - Property 'constraints' does not exist on type '(graphie: any, movable: any, options: any) => void'.
178	                        Interactive2.MovableLine.constraints.bound(),
179	                        // @ts-expect-error - TS2339 - Property 'constraints' does not exist on type '(graphie: any, movable: any, options: any) => void'.
180	                        Interactive2.MovableLine.constraints.snap(),
181	                        (newCoord, oldCoord: any) => {
182	                            // Calculate and apply proposed displacement
183	                            const delta = kvector.subtract(newCoord, oldCoord);
184	                            const proposedAsymptote = this._asymptote().map(
185	                                (coord) => kvector.add(coord, delta),
186	                            );
187	                            // Verify that resulting asymptote is valid for graph
188	                            if (model.extraAsymptoteConstraint) {
189	                                return model.extraAsymptoteConstraint(
190	                                    newCoord,
191	                                    oldCoord,
192	                                    this._coords(),
193	                                    proposedAsymptote,
194	                                    graph,
195	                                );
196	                            }
197	                            return true;
198	                        },
199	                    ]}
200	                    normalStyle={dashed}
201	                    highlightStyle={dashed}
202	                >
203	                    {asymptote.map((coord, i) => (
204	                        <MovablePoint
205	                            key={`asymptoteCoord-${i}`}
206	                            coord={coord}
207	                            static={true}
208	                            draw={null}
209	                            extendLine={true}
210	                            showHairlines={this.props.showHairlines}
211	                            hideHairlines={this.props.hideHairlines}
212	                            showTooltips={this.props.showTooltips}
213	                            isMobile={this.props.isMobile}
214	                        />
215	                    ))}
216	                </MovableLine>
217	            )
218	        );
219	    };
220	
221	    render(): React.ReactNode {
222	        const pointForCoord = (coord: any, i) => {
223	            return (
224	                <MovablePoint
225	                    key={i}
226	                    coord={coord}
227	                    static={this.props.static}
228	                    constraints={[
229	                        Interactive2.MovablePoint.constraints.bound(),
230	                        Interactive2.MovablePoint.constraints.snap(),
231	                        (coord: any) => {
232	                            // Always enforce that this is a function
233	                            const isFunction = this._coords().every(
234	                                (otherCoord, j) => {
235	                                    return (
236	                                        i === j ||
237	                                        !otherCoord ||
238	                                        !knumber.equal(coord[0], otherCoord[0])
239	                                    );
240	                                },
241	                            );
242	
243	                            // Evaluate this criteria before per-point
244	                            // constraints
245	                            if (!isFunction) {
246	                                return false;
247	                            }
248	
249	                            // Specific functions have extra per-point
250	                            // constraints
251	                            if (
252	                                this.props.model &&
253	                                this.props.model.extraCoordConstraint
254	                            ) {
255	                                const extraConstraint =
256	                                    this.props.model.extraCoordConstraint;
257	                                // Calculate resulting coords and verify that
258	                                // they're valid for this graph
259	                                const proposedCoords = deepClone(
260	                                    this._coords(),
261	                                );
262	                                const oldCoord = deepClone(proposedCoords[i]);
263	                                proposedCoords[i] = coord;
264	                                return extraConstraint(
265	                                    coord,
266	                                    oldCoord,
267	                                    proposedCoords,
268	                                    this._asymptote(),
269	                                    this.props.graph,
270	                                );
271	                            }
272	
273	                            return isFunction;
274	                        },
275	                    ]}
276	                    onMove={(newCoord, oldCoord) => {
277	                        let coords;
278	                        // Reflect over asymptote, if allowed
279	                        const asymptote = this._asymptote();
280	                        if (
281	                            asymptote &&
282	                            this.props.model.allowReflectOverAsymptote &&
283	                            isFlipped(newCoord, oldCoord, asymptote)
284	                        ) {
285	                            coords = this._coords().map((coord) => {
286	                                return kpoint.reflectOverLine(coord, asymptote);
287	                            });
288	                        } else {
289	                            coords = deepClone(this._coords());
290	                        }
291	                        coords[i] = newCoord;
292	                        this.props.onChange({
293	                            coords: coords,
294	                        });
295	                    }}
296	                    showHairlines={this.props.showHairlines}
297	                    hideHairlines={this.props.hideHairlines}
298	                    showTooltips={this.props.showTooltips}
299	                    isMobile={this.props.isMobile}
300	                />
301	            );
302	        };
303	        const points = this._coords().map(pointForCoord);
304	        const box = this.props.graph.box;
305	
306	        const imageDescription = this.props.graph.backgroundImage;
307	        let image = null;
308	        if (imageDescription.url) {
309	            const scale = box[0] / interactiveSizes.defaultBoxSize;
310	            // @ts-expect-error - TS2322 - Type 'Element' is not assignable to type 'null'.
311	            image = (
312	                // @ts-expect-error - TS2741 - Property 'alt' is missing in type '{ src: any; width: any; height: any; scale: number; }' but required in type 'Pick<Readonly<Props> & Readonly<{ children?: ReactNode; }>, "children" | "height" | "width" | "title" | "alt" | "trackInteraction" | "preloader" | "allowFullBleed" | "extraGraphie" | "overrideAriaHidden">'.
313	                <SvgImage
314	                    src={imageDescription.url}
315	                    // Don't allow zooming on an image that's being
316	                    // used as a graph background.
317	                    allowZoom={false}
318	                    width={imageDescription.width}
319	                    height={imageDescription.height}
320	                    scale={scale}
321	                />
322	            );
323	        }
324	
325	        return (
326	            <div
327	                className={"perseus-widget " + "perseus-widget-grapher"}
328	                style={{
329	                    width: box[0],
330	                    height: box[1],
331	                    boxSizing: "initial",
332	                }}
333	            >
334	                <div
335	                    className="graphie-container blank-background"
336	                    style={{
337	                        width: box[0],
338	                        height: box[1],
339	                    }}
340	                >
341	                    {image}
342	                    <Graphie {...this.props.graph}>
343	                        {this.props.model && this.renderPlot()}
344	                        {this.props.model && this.renderAsymptote()}
345	                        {this.props.model && points}
346	                    </Graphie>
347	                </div>
348	            </div>
349	        );
350	    }
351	}
