import {render, screen} from "@testing-library/react";
import * as React from "react";

import * as Dependencies from "../../../dependencies";
import {testDependencies} from "../../../testing/test-dependencies";
import {MafsGraph} from "../mafs-graph";
import {getBaseMafsGraphPropsForTests} from "../utils";

import {
    getAbsoluteValueCoefficients,
    getAbsoluteValueKeyboardConstraint,
} from "./absolute-value";

import type {InteractiveGraphState} from "../types";

const baseMafsGraphProps = getBaseMafsGraphPropsForTests();
const baseAbsoluteValueState: InteractiveGraphState = {
    type: "absolute-value",
    coords: [
        [0, 0],
        [2, 2],
    ],
    hasBeenInteractedWith: false,
    range: [
        [-10, 10],
        [-10, 10],
    ],
    snapStep: [1, 1],
};

describe("getAbsoluteValueCoefficients", () => {
    it("returns correct coefficients for a basic upward V", () => {
        const coeffs = getAbsoluteValueCoefficients([
            [0, 0],
            [2, 2],
        ]);
        expect(coeffs).toEqual({m: 1, h: 0, v: 0});
    });

    it("returns correct coefficients for a downward V", () => {
        const coeffs = getAbsoluteValueCoefficients([
            [1, 3],
            [3, 1],
        ]);
        expect(coeffs).toEqual({m: -1, h: 1, v: 3});
    });

    it("returns correct coefficients for a steeper slope", () => {
        const coeffs = getAbsoluteValueCoefficients([
            [0, 0],
            [1, 2],
        ]);
        expect(coeffs).toEqual({m: 2, h: 0, v: 0});
    });

    it("returns correct coefficients when vertex is not at origin", () => {
        const coeffs = getAbsoluteValueCoefficients([
            [1, 3],
            [2, 5],
        ]);
        expect(coeffs).toEqual({m: 2, h: 1, v: 3});
    });

    it("returns an infinite slope when both points share the same x-coordinate", () => {
        const coeffs = getAbsoluteValueCoefficients([
            [2, 0],
            [2, 4],
        ]);
        expect(coeffs).toEqual({m: Infinity, h: 2, v: 0});
    });

    it("treats left-arm and right-arm points as equivalent (same slope magnitude)", () => {
        const rightArm = getAbsoluteValueCoefficients([
            [0, 0],
            [2, 2],
        ]);
        const leftArm = getAbsoluteValueCoefficients([
            [0, 0],
            [-2, 2],
        ]);
        expect(rightArm?.m).toBe(leftArm?.m);
    });
});

describe("getAbsoluteValueKeyboardConstraint", () => {
    it("returns standard directions when no same-x conflict", () => {
        const coords: [number, number][] = [
            [0, 0],
            [2, 2],
        ];
        const constraint = getAbsoluteValueKeyboardConstraint(
            coords,
            [1, 1],
            0,
        );
        expect(constraint.right).toEqual([1, 0]);
        expect(constraint.left).toEqual([-1, 0]);
        expect(constraint.up).toEqual([0, 1]);
        expect(constraint.down).toEqual([0, -1]);
    });

    it("skips over same-x position when moving left", () => {
        // Moving point 0 from x=3 left toward x=2 (where point 1 is)
        const coords: [number, number][] = [
            [3, 0],
            [2, 2],
        ];
        const constraint = getAbsoluteValueKeyboardConstraint(
            coords,
            [1, 1],
            0,
        );
        // left one step would be [2, 0] — same x as point 1 — so skip to [1, 0]
        expect(constraint.left).toEqual([1, 0]);
    });

    it("skips over same-x position when moving right", () => {
        // Moving point 0 from x=1 right toward x=2 (where point 1 is)
        const coords: [number, number][] = [
            [1, 0],
            [2, 2],
        ];
        const constraint = getAbsoluteValueKeyboardConstraint(
            coords,
            [1, 1],
            0,
        );
        // right one step would be [2, 0] — same x as point 1 — so skip to [3, 0]
        expect(constraint.right).toEqual([3, 0]);
    });
});

describe("Absolute value graph screen reader", () => {
    beforeEach(() => {
        jest.spyOn(Dependencies, "getDependencies").mockReturnValue(
            testDependencies,
        );
    });

    it("renders with aria label for the graph", () => {
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={baseAbsoluteValueState}
            />,
        );
        const graph = screen.getByLabelText(
            "An absolute value on a coordinate plane.",
        );
        expect(graph).toBeInTheDocument();
    });

    it("renders with accessible description containing direction, vertex, and intercepts", () => {
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={baseAbsoluteValueState}
            />,
        );
        const graph = screen.getByLabelText(
            "An absolute value on a coordinate plane.",
        );
        expect(graph).toHaveAccessibleDescription(
            "The graph opens upward. Vertex is at the origin. The slope is 1.",
        );
    });

    it("renders vertex point with aria label", () => {
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={baseAbsoluteValueState}
            />,
        );
        const points = screen.getAllByRole("button");
        expect(points[0]).toHaveAccessibleName("Vertex point at 0 comma 0.");
    });

    it("renders arm point with aria label and slope description", () => {
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={baseAbsoluteValueState}
            />,
        );
        const points = screen.getAllByRole("button");
        expect(points[1]).toHaveAccessibleName("Point on arm at 2 comma 2.");
        expect(points[1]).toHaveAccessibleDescription("The slope is 1.");
    });

    it("includes interactive elements description with both points and the slope", () => {
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={baseAbsoluteValueState}
            />,
        );
        const description = screen.getByText(
            "Interactive elements: Absolute value graph with vertex point at 0 comma 0, arm point at 2 comma 2 and slope of 1.",
        );
        expect(description).toBeInTheDocument();
    });

    it("describes a downward graph that opens with two x-intercepts", () => {
        // Vertex (0, 2) above the x-axis, arm point (1, 0) below it → m = -2
        // (opens downward), x-intercepts where |x| = 1, y-intercept at the
        // vertex.
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={{
                    ...baseAbsoluteValueState,
                    coords: [
                        [0, 2],
                        [1, 0],
                    ],
                }}
            />,
        );
        const graph = screen.getByLabelText(
            "An absolute value on a coordinate plane.",
        );
        expect(graph).toHaveAccessibleDescription(
            "The graph opens downward. Vertex is at 0 comma 2. The X-intercepts are at -1 comma 0 and 1 comma 0. The Y-intercept is at 0 comma 2. The slope is -2.",
        );
    });

    it("updates aria labels when coordinates change", () => {
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={{
                    ...baseAbsoluteValueState,
                    coords: [
                        [1, 3],
                        [3, 5],
                    ],
                }}
            />,
        );
        const points = screen.getAllByRole("button");
        expect(points[0]).toHaveAccessibleName("Vertex point at 1 comma 3.");
        expect(points[1]).toHaveAccessibleName("Point on arm at 3 comma 5.");
    });
});

// TODO(LEMS-3995, post-PR-7): route the absolute-value SR-tree summary through buildPointAriaLabel once new locale string keys land.
describe("Absolute value graph pointLabels", () => {
    beforeEach(() => {
        jest.spyOn(Dependencies, "getDependencies").mockReturnValue(
            testDependencies,
        );
    });

    it("uses custom pointLabels in each point's accessible name", () => {
        // Arrange, Act
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={{...baseAbsoluteValueState, pointLabels: ["A", "B"]}}
            />,
        );

        // Assert
        expect(
            screen.getByRole("button", {name: "Point A at 0 comma 0."}),
        ).toBeInTheDocument();
        expect(
            screen.getByRole("button", {name: "Point B at 2 comma 2."}),
        ).toBeInTheDocument();
    });

    it("falls back to the default semantic label for indices without a custom label", () => {
        // Arrange, Act — only the vertex is named
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={{...baseAbsoluteValueState, pointLabels: ["A"]}}
            />,
        );

        // Assert
        expect(
            screen.getByRole("button", {name: "Point A at 0 comma 0."}),
        ).toBeInTheDocument();
        expect(
            screen.getByRole("button", {name: "Point on arm at 2 comma 2."}),
        ).toBeInTheDocument();
    });

    // The editor encodes "only the arm point named" as `["", "B"]`.
    // An empty string at any index must fall back to the semantic default.
    it("falls back to the default semantic label for explicit empty-string entries", () => {
        // Arrange, Act
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={{...baseAbsoluteValueState, pointLabels: ["", "B"]}}
            />,
        );

        // Assert
        expect(
            screen.getByRole("button", {name: "Vertex point at 0 comma 0."}),
        ).toBeInTheDocument();
        expect(
            screen.getByRole("button", {name: "Point B at 2 comma 2."}),
        ).toBeInTheDocument();
    });

    it("falls back to the default semantic label for truthy non-string entries (defensive against malformed hand-authored JSON bypassing the parser)", () => {
        // Arrange, Act
        render(
            <MafsGraph
                {...baseMafsGraphProps}
                state={{
                    ...baseAbsoluteValueState,
                    // eslint-disable-next-line no-restricted-syntax -- cast simulates malformed JSON the parser would reject
                    pointLabels: [42, "B"] as unknown as string[],
                }}
            />,
        );

        // Assert
        expect(
            screen.getByRole("button", {name: "Vertex point at 0 comma 0."}),
        ).toBeInTheDocument();
        expect(
            screen.getByRole("button", {name: "Point B at 2 comma 2."}),
        ).toBeInTheDocument();
    });
});

